const https = require("https");

async function run() {
  const taskId = "retry-logic-task-custom_retry_and_logging__Fr2oJVE";
  const payload = { userId: "user_123" };
  const accessToken = process.env.TRIGGER_ACCESS_TOKEN;

  if (!accessToken) {
    console.error("TRIGGER_ACCESS_TOKEN is missing");
    process.exit(1);
  }

  const data = JSON.stringify({ payload });

  const options = {
    hostname: "api.trigger.dev",
    port: 443,
    path: `/api/v1/tasks/${taskId}/trigger`,
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": `Bearer ${accessToken}`,
      "Content-Length": data.length,
    },
  };

  const req = https.request(options, (res) => {
    let responseBody = "";
    res.on("data", (chunk) => {
      responseBody += chunk;
    });
    res.on("end", () => {
      if (res.statusCode >= 200 && res.statusCode < 300) {
        try {
          const json = JSON.parse(responseBody);
          console.log(`Run ID: ${json.id}`);
        } catch (e) {
          console.error("Failed to parse response:", responseBody);
        }
      } else {
        console.error(`Request failed with status ${res.statusCode}:`, responseBody);
        process.exit(1);
      }
    });
  });

  req.on("error", (error) => {
    console.error("Request error:", error);
    process.exit(1);
  });

  req.write(data);
  req.end();
}

run();

